from itertools import permutations


class Solution:
    def minMovesToSeat(self, seats, students):
        n = len(seats)
        if n > 7:
            s = sorted(seats)
            t = sorted(students)
            return sum(abs(a - b) for a, b in zip(s, t))
        best = None
        for perm in permutations(students):
            cost = sum(abs(seats[i] - perm[i]) for i in range(n))
            if best is None or cost < best:
                best = cost
        return best

