var minMovesToSeat = function(seats, students) {
    const s = seats.slice().sort((a, b) => a - b);
    const t = students.slice().sort((a, b) => a - b);
    let total = 0;
    for (let i = 0; i < s.length; i++) total += Math.abs(s[i] - t[i]);
    return total;
};
